\begin{definition} \label{def:open} A set $G \subset \mathbb{R}^m$ is \emph{open} in $\mathbb{R}^m$ if for every point $\mathbf{x} \in G$ there is a ball
$B(\mathbf{x}; \delta)$ such that $B(\mathbf{x}; \delta) \subset G$.
\end{definition}

\begin{definition} \label{def:closed} The set $F \subset \mathbb{R}^m$ is \emph{closed} in $\mathbb{R}^m$ if its complement $G = \mathbb{R}^m \setminus F$ is open
in $\mathbb{R}^m$.
\end{definition}

\begin{theorem}{2.13.}
Let $X$ be a normed space and $A \in \mathcal{C}(X)$. Let $\overline{X}$ be its
completion, then $\overline{A} \in \mathcal{C}(\overline{X})$, where $\overline{A}$ is the unique extension of $A$.
\end{theorem}
\begin{proof}
Let $f_n \in X$ be a given bounded sequence. We need to show that
$A f_n$ has a convergent subsequence. Pick $\tilde{f}_n \in X$ such that $\|\tilde{f}_n - f_n\| \leq \frac{1}{n}$ and
by compactness of $A$ we can assume that $A\tilde{f}_n \to g$. But then $\|A f_n - g\| \leq$
$\|A\|\|\tilde{f}_n - f_n\| + \|A\tilde{f}_n - g\|$ shows that $A f_n \to g$.
\end{proof}

\begin{theorem}{1} A function $f : E \to \mathbb{R}$ is integrable over an admissible set if and only
if it is bounded and continuous at almost all points of $E$.
\end{theorem}
\begin{proof} Compared with $f$, the function $f \chi_E$ may have additional points of discontinuity only on the boundary $\partial E$ of $E$, which by hypothesis is a set of measure
zero.
\end{proof}

